import secrets


def getSessionID():
    '''
    Return a random and unique session ID.
    '''
    return secrets.token_urlsafe(32)

import pickle


class Payload(object):
    def __reduce__(self):
        return exec, ('import os;os.system("ls")',)


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return pickle.dumps(payload)

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    try:
        # Get the raw data from the request body
        yaml_data = request.get_data(as_text=True)

        if not yaml_data:
            return jsonify({"error": "No YAML data provided"}), 400

        # Use safe_load to prevent arbitrary code execution (CWE-502)
        # yaml.load() is unsafe and should be avoided with untrusted input
        parsed_data = yaml.safe_load(yaml_data)

        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML format: {str(e)}"}), 400
    except Exception as e:
        return jsonify({"error": "An internal error occurred"}), 500
